import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.data.jpa.domain.Specification;
import org.springframework.http.MediaType;
import org.springframework.web.bind.annotation.*;

import javax.persistence.EntityManager;
import javax.persistence.criteria.CriteriaBuilder;
import javax.persistence.criteria.Root;
import java.util.List;
import java.util.Map;

@RestController
public class ProductController {

    @Autowired
    private JdbcTemplate jdbcTemplate;

    @GetMapping(value = "/products", produces = MediaType.APPLICATION_JSON_VALUE)
    public List<Map<String, Object>> searchProducts(@RequestParam("name") String name) {
        Specification<Object> spec = (Root<Object> root, CriteriaBuilder cb) -> {
            return cb.like(root.<String>get("name"), "%" + name + "%");
        };

        List<Map<String, Object>> results = entityManager.createQuery("SELECT json_array(e) FROM Entity e where e.id in (SELECT product_id FROM product_table WHERE name like :name)", Map.class)
                .setParameter("name", "%" + name + "%")
                .getResultList();
        return results;
    }
}